sql_query:
SELECT "Treatment regimen"
FROM clinical_trials
WHERE "Cancer type" = 'Multiple Myeloma' AND "Type of combination" = 'ICI+TKI';

ground_truth_sql:
WITH base AS (
SELECT "NCT", "PubMed ID", "Trial name", "Treatment regimen" AS source_value FROM clinical_trials
WHERE "Cancer type" = 'Multiple Myeloma' AND "Type of combination" = 'ICI+TKI'
)
SELECT "NCT", "PubMed ID", "Trial name", source_value, derive_tki_agents(source_value) AS "tki_agents"
FROM base;
